INSERT INTO templates (name, description, is_default, hosts_content, config_content, created_by, created_at, updated_at)
VALUES (
    'labclaw-production',
    'Labclaw production cluster template with Cilium network, containerd runtime, and full addon stack',
    true,
    '# ''etcd'' cluster should have odd member(s) (1,3,5,...)\n[etcd]\n192.168.1.1\n192.168.1.2\n192.168.1.3\n\n# master node(s)\n[kube_master]\n192.168.1.1 k8s_nodename=''master-01''\n192.168.1.2 k8s_nodename=''master-02''\n\n# work node(s)\n[kube_node]\n192.168.1.4 k8s_nodename=''worker-01''\n192.168.1.5 k8s_nodename=''worker-02''\n\n# [optional] harbor server\n[harbor]\n#192.168.1.8 NEW_INSTALL=false\n\n# [optional] loadbalance for accessing k8s from outside\n[ex_lb]\n#192.168.1.6 LB_ROLE=backup EX_APISERVER_VIP=192.168.1.250 EX_APISERVER_PORT=8443\n#192.168.1.7 LB_ROLE=master EX_APISERVER_VIP=192.168.1.250 EX_APISERVER_PORT=8443\n\n# [optional] ntp server\n[chrony]\n#192.168.1.1\n\n[all:vars]\nSECURE_PORT="6443"\nCONTAINER_RUNTIME="containerd"\nCLUSTER_NETWORK="cilium"\nPROXY_MODE="iptables"\nSERVICE_CIDR="10.19.0.0/16"\nCLUSTER_CIDR="172.19.0.0/16"\nNODE_PORT_RANGE="30000-32767"\nCLUSTER_DNS_DOMAIN="cluster.local"\nbin_dir="/opt/kube/bin"\nbase_dir="/etc/kubeasz"\nca_dir="/etc/kubernetes/ssl"\nk8s_nodename=''''\nansible_python_interpreter=/usr/bin/python3\nansible_user="root"\nansible_become="yes"\n',
    '############################\n# prepare\n############################\nINSTALL_SOURCE: "offline"\nOS_HARDEN: false\n\n############################\n# role:deploy\n############################\nCA_EXPIRY: "876000h"\nCERT_EXPIRY: "438000h"\nCHANGE_CA: false\nCLUSTER_NAME: "labclaw"\nCONTEXT_NAME: "context-{{ CLUSTER_NAME }}"\nK8S_VER: "1.34.3"\nK8S_NODENAME: "{%- if k8s_nodename != '''' -%} \\\n                    {{ k8s_nodename|replace(''_'', ''-'')|lower }} \\\n               {%- else -%} \\\n                    k8s-{{ inventory_hostname|replace(''.'', ''-'') }} \\\n               {%- endif -%}"\nENABLE_SETTING_HOSTNAME: true\n\n############################\n# role:etcd\n############################\nETCD_DATA_DIR: "/workspace/var/lib/etcd"\nETCD_WAL_DIR: ""\n\n############################\n# role:runtime\n############################\nENABLE_MIRROR_REGISTRY: false\nINSECURE_REG:\n  - "http://registry.ccoe.tech"\n  - "https://registry.ccoe.tech"\n  - "https://registry.ccoe.vip"\n  - "https://registry.cic.cmbchina.cn"\nSANDBOX_IMAGE: "registry.ccoe.tech/ks/easzlab/pause:3.10"\nCONTAINERD_ROOT_DIR: "/workspace/var/lib/containerd"\nCONTAINERD_STATE_DIR: "/workspace/run/containerd"\nCONTAINERD_CONFIG_DIR: "/workspace/etc/containerd"\nCONTAINERD_SERVICE_NAME: "containerd.service"\nDOCKER_STORAGE_DIR: "/workspace/var/lib/docker"\nDOCKER_ENABLE_REMOTE_API: false\n\n############################\n# role:kube-master\n############################\nMASTER_CERT_HOSTS:\n  - "192.168.1.1"\n  - "192.168.1.2"\n  - "192.168.1.3"\n  - "labclaw.ccoe.tech"\n  - "k8s.labclaw.ccoe.tech"\n  - "api.labclaw.ccoe.tech"\n  - "lb.labclaw.ccoe.tech"\n  - "ops.labclaw.ccoe.tech"\nNODE_CIDR_LEN: 24\nENABLE_CLUSTER_AUDIT: true\n\n############################\n# role:kube-node\n############################\nKUBELET_ROOT_DIR: "/workspace/var/lib/kubelet"\nMAX_PODS: 310\nKUBE_RESERVED_ENABLED: "no"\nSYS_RESERVED_ENABLED: "no"\n\n############################\n# role:network\n############################\nFLANNEL_BACKEND: "vxlan"\nDIRECT_ROUTING: false\nflannel_ver: "v0.27.3"\nCALICO_ENABLE_OVERLAY: "Always"\nIP_AUTODETECTION_METHOD: "can-reach={{ groups[''kube_master''][0] }}"\nCALICO_NETWORKING_BACKEND: "bird"\nCALICO_RR_ENABLED: false\nCALICO_RR_NODES: []\ncalico_ver: "v3.28.4"\ncalico_ver_main: "{{ calico_ver.split(''.'')[0] }}.{{ calico_ver.split(''.'')[1] }}"\ncilium_ver: "1.17.4"\ncilium_connectivity_check: true\ncilium_hubble_enabled: true\ncilium_hubble_ui_enabled: true\nkube_ovn_ver: "v1.11.5"\nOVERLAY_TYPE: "full"\nFIREWALL_ENABLE: false\nkube_router_ver: "v1.5.4"\n\n############################\n# role:cluster-addon\n############################\ndns_install: "yes"\ncorednsVer: "1.12.4"\nENABLE_LOCAL_DNS_CACHE: false\ndnsNodeCacheVer: "1.26.4"\nLOCAL_DNS_CACHE: "10.19.0.53"\nmetricsserver_install: "yes"\nmetricsVer: "v0.8.0"\ndashboard_install: "yes"\ndashboardVer: "7.14.0"\nlocal_path_provisioner_install: "yes"\nlocal_path_provisioner_ver: "v0.0.31"\nlocal_path_storage_class: "local-path"\nlocal_path_provisioner_dir: "/workspace/opt/local-path-provisioner"\nnfs_provisioner_install: "yes"\nnfs_provisioner_namespace: "kube-system"\nnfs_provisioner_ver: "v4.0.2"\nnfs_storage_class: "nfs"\nnfs_server: "192.168.1.10"\nnfs_path: "/labclawHome"\nopenebs_install: "yes"\nopenebs_ver: "4.3.2"\nopenebs_namespace: "openebs"\nopenebs_hostpath: "/workspace/var/openebs/local"\nopenebs_hostpath_storage_class: "openebs-hostpath"\nopenebs_lvm_storage_class: "openebs-lvmpv"\nopenebs_lvm_vg: "vg_k8s"\nprom_install: "no"\nprom_namespace: "monitor"\nprom_storage_class: ""\nprom_chart_ver: "75.7.0"\nminio_install: "no"\nminio_namespace: "minio"\nminio_storage_class: "{{ openebs_lvm_storage_class }}"\nminio_chart_ver: "7.1.1"\nminio_root_user: "3aea61ca94177dx"\nminio_root_password: "0f3b19e46dd3aea61ca94177d"\nminio_pool_servers: 4\nminio_pool_size: 10Gi\nminio_tls_enabled: false\nminio_with_global_cert: false\nnacos_install: "no"\nnacos_namespace: "nacos"\nnacos_mysql_host: "semisync-mysql-cluster-mysql"\nnacos_mysql_db: "nacos"\nnacos_mysql_port: "3306"\nnacos_mysql_user: "__dbuser__"\nnacos_mysql_password: "__yourpassword__"\nnacos_storage_class: "{{ openebs_lvm_storage_class }}"\nrocketmq_install: "no"\nrocketmq_namespace: "rocketmq"\nrocketmq_storage_class: "{{ openebs_lvm_storage_class }}"\nnetwork_check_enabled: false\nnetwork_check_schedule: "*/5 * * * *"\nkubeblocks_ver: "1.0.1"\nkubeblocks_install: "no"\ningress_nginx_install: "no"\ningress_nginx_namespace: "ingress-nginx"\ningress_nginx_ver: "4.13.0"\ningress_nginx_metrics_enabled: true\nargocd_install: "yes"\n\n############################\n# role:harbor\n############################\nHARBOR_VER: "v2.12.4"\nHARBOR_DOMAIN: "harbor.easzlab.io.local"\nHARBOR_PATH: /var/data\nHARBOR_TLS_PORT: 8443\nHARBOR_REGISTRY: "{{ HARBOR_DOMAIN }}:{{ HARBOR_TLS_PORT }}"\nHARBOR_SELF_SIGNED_CERT: true\nHARBOR_WITH_TRIVY: false\n',
    1,
    NOW(),
    NOW()
);
